def process_payment(user, cart_items, payment_details):
    role = getattr(user, "role", None) if not isinstance(user, dict) else user.get("role")
    discounts = {
        "basic": 0.0,
        "premium": 0.15,
        "enterprise": 0.30,
    }

    if role not in discounts:
        raise ValueError("Invalid user role")

    total = 0.0
    for item in cart_items or []:
        if isinstance(item, dict):
            price = float(item.get("price", 0))
            quantity = int(item.get("quantity", 1))
        else:
            price = float(getattr(item, "price", 0))
            quantity = int(getattr(item, "quantity", 1))
        total += price * quantity

    discount_rate = discounts[role]
    discount_amount = total * discount_rate
    final_total = total - discount_amount

    if not payment_details:
        raise ValueError("Missing payment details")

    payment_method = payment_details.get("method") if isinstance(payment_details, dict) else getattr(payment_details, "method", None)
    if not payment_method:
        raise ValueError("Invalid payment details")

    payment_result = {
        "status": "success",
        "user_role": role,
        "subtotal": round(total, 2),
        "discount_percentage": int(discount_rate * 100),
        "discount_amount": round(discount_amount, 2),
        "total": round(final_total, 2),
        "payment_method": payment_method,
    }

    return payment_result